VALUES
  ('fire-eq-eng-moex-01053', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列何者屬於公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法中，所稱之「自反應物質及有機 過氧化物」？', '["硝酸酯類", "過氧化氫", "烷基鋁", "硝酸鹽類"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01054', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列何者，不是各類場所消防安全設備設置標準第四編「公共危險物品等場所消防設計及消防安全設備」 所規定適用之場所？', '["加油站", "天然氣儲槽", "爆竹煙火製造場所", "飛機修理廠"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01055', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列何者，屬各類場所消防安全設備設置標準第四編「公共危險物品等場所消防設計及消防安全設備」 所規定之「第五種滅火設備」？', '["室內消防栓", "水霧滅火設備", "乾粉滅火設備", "滅火器"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01056', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '加油站所在建築物，其2樓以上供其他用途使用者，應設置何種設備？', '["標示設備", "警報設備", "自動撒水設備", "乾粉滅火設備"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01057', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「消防幫浦加壓送水裝置等及配管摩擦損失計算基準」規定，有關幫浦之敘述，何者錯誤？', '["與幫浦相連接之配管系中所使用之凸緣須使用CNS790、791及792等鐵金屬製管凸緣基準尺度", "幫浦本體所使用之材料為青銅鑄件應符合CNS3828之規格或使用具同等以上強度，且有耐蝕性者", "幫浦之吸水性能在額定出水量每分鐘3000公升時，其最大吸水全揚程為4.5公尺（m）以上，且不得 有異常現象", "幫浦本體必須能耐最高水壓之1.5倍以上，且加壓3分鐘後，各部位仍無洩漏現象才算合格"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01058', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」規定，蓄壓式鹵化烴滅火藥劑儲存容器性能檢查， 有關滅火藥劑量以水平液面計測定時之敘述，何者錯誤？', '["使用方法為插入水平液面計電源開關，檢查其電壓值，使容器維持平常之狀態，將容器置於液面計探 針與放射源之間，緩緩使液面計檢出部上下方向移動，當發現儀表指針振動差異較大時，由該位置即 可求出自容器底部起之藥劑存量高度，液面高度與藥劑量之換算，應使用專用之換算尺為之", "判定方法為將藥劑量之測定結果與重量表、圖面明細表或原廠技術手冊規範核對，其差值應在充填值 10%以下", "當滅火藥劑量或容器內壓減少時，應迅即進行調查，並採取必要之措施", "不得任意卸取放射線源（鈷60），鈷60有效使用年限約為5年，如已超過時，應即時連絡專業單位處 理或更換"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01059', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「複合用途建築物判斷基準」規定，複合用途建築物中，甲類場所樓地板面積合計未滿多少平方公 尺時，視為各類場所消防安全設備設置標準第十二條第五款第二目之複合用途建築物？', '["三百", "三百五十", "四百", "五百"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01060', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「消防機關辦理建築物消防安全設備審查及查驗作業基準」規定，有關建築物消防安全設備圖說 審查作業程序之敘述，何者正確？', '["消防機關受理申請案於掛號分案後，即排定審查日期，通知該件建築物起造人及消防安全設備設計人， 並由消防安全設備設計人攜帶其資格證件及當地建築主管機關審訖建築圖說，配合審查，消防安全設備 設計人無正當理由未會同審查者，得予退件", "變更設計或變更用途，非系統式設備僅變動滅火器、緊急照明燈等簡易設備者，消防安全設備設計人 不得免配合審查", "供公眾使用建築物或構造複雜者之消防安全設備圖說審查之期限，得視需要延長，並通知申請人，最 長不得超過三十日", "消防圖說經審訖修改完成，送消防機關加蓋驗訖章後，消防機關留存三份，餘交起造人 (即申請人) 留存"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01061', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「滅火器用滅火藥劑認可基準」規定之敘述，何者正確？', '["化學泡沫滅火劑分為甲種藥劑、乙種藥劑等2種，甲種藥劑所含碳酸氫鈉（NaHCO）應在16%以上 3", "灌裝機械泡沫滅火劑之滅火器，於20℃使其作動時，泡沫膨脹比在5倍以上，且25%還原時間在1分 鐘以上", "乾粉滅火劑粉末細度，應能通過CNS386試驗篩之80篩網目（mesh）80%以上者", "當有151~200批次滅火器送一般試驗時，其嚴格試驗抽樣數為5個樣品數"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01062', 'fire-eq-eng', 'fire-eq-eng-moex-098-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「出口標示燈及避難方向指示燈認可基準」規定之敘述，何者錯誤？', '["內部配線應做好防護措施，與電源接裝之出線，其截面積不得小於0.75 mm2", "內置型引導燈具緊急電源時間應維持90分鐘以上", "燈具配線與電源側電線之連接點溫度上升變化應在40℃以下", "使用直流500 V高阻計，測量帶電部分與不帶電金屬間之絕緣電阻，均應為5 MΩ以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "525d139079ff", "answer_pdf_sha1": "55834ab1f2a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
